309: // Run repeatedly uses the reflector's ListAndWatch to fetch all the
310: // objects and subsequent deltas.
311: // Run will exit when stopCh is closed.
312: func (r *Reflector) Run(stopCh <-chan struct{}) {
313: 	klog.V(3).Infof("Starting reflector %s (%s) from %s", r.typeDescription, r.resyncPeriod, r.name)
314: 	wait.BackoffUntil(func() {
315: 		if err := r.ListAndWatch(stopCh); err != nil {
316: 			r.watchErrorHandler(r, err)
317: 		}
318: 	}, r.backoffManager, true, stopCh)
319: 	klog.V(3).Infof("Stopping reflector %s (%s) from %s", r.typeDescription, r.resyncPeriod, r.name)
320: }
